def _safe_note_path(note_rel: str, base: Path = None) -> Path | None:
    """Resolve a note relative path and verify it stays within the notes directory.
    Returns the resolved Path if safe, or None if traversal detected."""
    if base is None:
        base = CC_NOTES
    if not note_rel or note_rel.startswith("/"):
        return None
    candidate = (base / note_rel).resolve()
    try:
        candidate.relative_to(base.resolve())
    except ValueError:
        return None  # traversal detected
    return candidate

def _path_is_within(path: Path, base: Path) -> bool:
    """Return True when path resolves inside base, not just under a string prefix."""
    try:
        path.resolve().relative_to(base.resolve())
        return True
    except (OSError, ValueError):
        return False

# ── Filesystem access control ────────────────────────────────────────────────
_SENSITIVE_PATHS = {".ssh", ".gnupg", ".aws", ".kube", ".netrc", ".npmrc",
                    ".docker", ".config/gcloud", ".config/gh"}
_BLOCKED_SYSTEM_PATHS = frozenset({
    "/etc/shadow", "/etc/sudoers", "/etc/master.passwd",
    "/private/etc/shadow", "/private/etc/sudoers",
    "/var/db/sudo", "/private/var/db/sudo",
})
_BLOCKED_SYSTEM_PREFIXES = (
    "/etc/ssh/", "/private/etc/ssh/",
    "/var/run/secrets/", "/run/secrets/",
)

def _is_path_allowed(p: Path) -> bool:
    """Check if a resolved path is safe to access via file APIs."""
    try:
        resolved = p.resolve()
    except (OSError, ValueError):
        return False
    resolved_str = str(resolved)
    if resolved_str in _BLOCKED_SYSTEM_PATHS:
        return False
    if any(resolved_str.startswith(pfx) for pfx in _BLOCKED_SYSTEM_PREFIXES):
        return False
    home = Path.home().resolve()
    try:
        rel = resolved.relative_to(home)
        parts = rel.parts
        for sensitive in _SENSITIVE_PATHS:
            sens_parts = Path(sensitive).parts
            if parts[:len(sens_parts)] == sens_parts:
                return False
    except ValueError:
        pass
    return True

# ── Authentication ───────────────────────────────────────────────────────────
_AUTH_TOKEN_FILE = _amux_home / "auth_token"
def _load_or_create_auth_token() -> str:
    env_token = os.environ.get("AMUX_AUTH_TOKEN", "")
    if env_token:
        return "" if env_token.lower() == "none" else env_token
    if _AUTH_TOKEN_FILE.exists():
        token = _AUTH_TOKEN_FILE.read_text().strip()
        if token:
            return token
    import secrets as _secrets
    token = _secrets.token_urlsafe(32)
    _amux_home.mkdir(parents=True, exist_ok=True)
    _AUTH_TOKEN_FILE.write_text(token + "\n")
    os.chmod(str(_AUTH_TOKEN_FILE), 0o600)
    return token

AUTH_TOKEN = _load_or_create_auth_token()

# Dedicated guard token for DESTRUCTIVE session ops (delete/archive). It is
# embedded only in the served dashboard HTML, so a human using the dashboard
# has it but a session/agent hitting the local API does not — this is what
# stops sessions from deleting other sessions. Derived from the persisted
# AUTH_TOKEN so it's stable across restarts, but distinct and never returned
# by any API endpoint. Override for trusted automation with
# AMUX_ALLOW_AGENT_SESSION_DELETE=1 in ~/.amux/server.env.
import hashlib as _hashlib
_UI_TOKEN = _hashlib.sha256(("amux-ui-guard:" + AUTH_TOKEN).encode()).hexdigest()[:40]


def _session_destructive_allowed(headers) -> bool:
    """True if a delete/archive is authorized: either explicit automation
    opt-in, or the request carries the dashboard UI token (i.e. a human acting
    in the dashboard). Sessions/agents calling the API directly have neither."""
    if os.environ.get("AMUX_ALLOW_AGENT_SESSION_DELETE", "") in ("1", "true", "yes"):
        return True
    try:
        return headers.get("X-Amux-UI-Token", "") == _UI_TOKEN
    except Exception:
        return False


# ── PostHog server-side telemetry ────────────────────────────────────────────
# Emits events for signals only the backend observes (YOLO auto-answers,
# stale-session restarts, crashes). No-op when POSTHOG_KEY is unset.
def _posthog_emit(event: str, props: dict = None, distinct_id: str = ""):
    key = os.environ.get("POSTHOG_KEY", "")
    if not key:
        return
    try:
        import urllib.request as _ur, json as _j, ssl as _ssl
        host = os.environ.get("POSTHOG_HOST", "https://us.i.posthog.com").rstrip("/")
        payload = {
            "api_key": key,
            "event": event,
            "distinct_id": distinct_id or "amux-server",
            "properties": {"source": "amux-server", **(props or {})},
        }
        req = _ur.Request(
            f"{host}/capture/",
            data=_j.dumps(payload).encode(),
            headers={"Content-Type": "application/json"},
        )
        ctx = _ssl.create_default_context()
        ctx.check_hostname = False
        ctx.verify_mode = _ssl.CERT_NONE
        _ur.urlopen(req, timeout=3, context=ctx).read()
    except Exception:
        pass


