def _get_slash_commands():
    import pathlib as _p
    cmds = [{"cmd": c, "desc": d} for c, d in _BUILTIN_SLASH_COMMANDS]
    seen = {c for c, _ in _BUILTIN_SLASH_COMMANDS}
    for d in [_p.Path.home() / ".claude" / "commands", _p.Path(".")  / ".claude" / "commands"]:
        if not d.is_dir():
            continue
        for f in sorted(d.glob("*.md")):
            name = "/" + f.stem
            if name in seen:
                continue
            seen.add(name)
            desc = ""
            try:
                text = f.read_text()
                if text.startswith("---"):
                    fm_end = text.find("---", 3)
                    if fm_end > 0:
                        for line in text[3:fm_end].splitlines():
                            if line.startswith("description:"):
                                desc = line.split(":", 1)[1].strip()
                                break
            except Exception:
                pass
            cmds.append({"cmd": name, "desc": desc})
    return cmds


def _init_db():
    """Create SQLite tables if they don't exist."""
    db = get_db()
    db.executescript(_DB_SCHEMA)
    # Ensure built-in statuses have correct positions (idempotent for existing DBs)
    for pos, (sid, label) in enumerate([
        ("backlog",   "Backlog"),
        ("todo",      "To Do"),
        ("doing",     "In Progress"),
        ("review",    "In Review"),
        ("done",      "Done"),
        ("verified",  "Verified"),
        ("discarded", "Discarded"),
    ]):
        db.execute(
            "INSERT INTO statuses (id, label, position, is_builtin) VALUES (?, ?, ?, 1)"
            " ON CONFLICT(id) DO UPDATE SET position = ?, is_builtin = 1",
            (sid, label, pos, pos),
        )
    db.commit()
    # Migrations: add columns that may not exist on older DBs
    for migration in [
        "ALTER TABLE issues ADD COLUMN owner_type TEXT NOT NULL DEFAULT 'human'",
        "ALTER TABLE issues ADD COLUMN due_time TEXT",
        "ALTER TABLE issues ADD COLUMN pinned INTEGER NOT NULL DEFAULT 0",
        "ALTER TABLE schedules ADD COLUMN run_count INTEGER NOT NULL DEFAULT 0",
        "ALTER TABLE schedules ADD COLUMN schedule_expr TEXT",
        "ALTER TABLE schedules ADD COLUMN watch INTEGER NOT NULL DEFAULT 0",
        "ALTER TABLE schedules ADD COLUMN watch_timeout INTEGER NOT NULL DEFAULT 120",
        "ALTER TABLE schedules ADD COLUMN done_pattern TEXT",
        "ALTER TABLE schedules ADD COLUMN done_action TEXT NOT NULL DEFAULT 'disable'",
        # Event triggers: wake a schedule's session when something changes (closed-loop
        # orchestration), in addition to (not instead of) the cron schedule_expr heartbeat.
        # trigger_on is a comma-separated set of event names (e.g. 'session_idle,board').
        "ALTER TABLE schedules ADD COLUMN trigger_on TEXT",
        "ALTER TABLE schedules ADD COLUMN trigger_cooldown INTEGER NOT NULL DEFAULT 120",
        # Optional comma-separated allowlist of sessions whose events count for this
        # trigger (empty/null = any session). Scopes session_idle to e.g. the sessions
        # an orchestrator manages, so unrelated fleet activity doesn't wake it.
        "ALTER TABLE schedules ADD COLUMN trigger_sessions TEXT",
        "ALTER TABLE graph_nodes ADD COLUMN source_path TEXT NOT NULL DEFAULT ''",
        "ALTER TABLE issues ADD COLUMN gcal_event_id TEXT",
        "ALTER TABLE issues ADD COLUMN pos REAL NOT NULL DEFAULT 0",
        "ALTER TABLE issues ADD COLUMN notified INTEGER NOT NULL DEFAULT 0",
        "ALTER TABLE schedules ADD COLUMN kind TEXT NOT NULL DEFAULT 'tmux'",
    ]:
        try:
            db.execute(migration)
            db.commit()
        except Exception:
            pass  # column already exists
    # One-time migration: import existing flat skill files into SQLite
    skills_dir = CC_HOME / "skills"
    if skills_dir.exists():
        for f in skills_dir.glob("*.md"):
            try:
                content = f.read_text(errors="replace")
                db.execute(
                    "INSERT OR IGNORE INTO skills(name, content, updated) VALUES(?,?,?)",
                    (f.stem, content, int(f.stat().st_mtime)),
                )
            except Exception:
                pass
        db.commit()


