_SHARE_JS = r"""
const API = '/api/share/' + document.body.dataset.token;
const HAS_FILES = document.body.dataset.files === '1';
const HAS_NOTES = document.body.dataset.notes === '1';
let pollId;
function switchTab(name) {
  document.querySelectorAll('.tab').forEach(t => t.classList.toggle('active', t.textContent.trim().toLowerCase() === name));
  document.querySelectorAll('.panel').forEach(p => p.classList.toggle('active', p.id === 'panel-' + name));
  if (name === 'output') startPoll(); else stopPoll();
  if (name === 'files') loadFiles('');
  if (name === 'notes') loadNotes();
}
async function loadOutput() {
  try {
    const r = await fetch(API + '/peek?lines=300');
    const d = await r.json();
    const el = document.getElementById('output');
    el.textContent = d.output || '(no output)';
    el.scrollTop = el.scrollHeight;
  } catch(e) { console.error(e); }
}
async function loadInfo() {
  try {
    const r = await fetch(API + '/info');
    const d = await r.json();
    document.getElementById('status-dot').classList.toggle('running', d.running);
    if (d.desc) document.getElementById('session-desc').textContent = d.desc;
  } catch(e) {}
}
function startPoll() { stopPoll(); loadOutput(); pollId = setInterval(loadOutput, 3000); }
function stopPoll() { if (pollId) clearInterval(pollId); pollId = null; }
// Files
let filePath = '';
async function loadFiles(p) {
  if (!HAS_FILES) return;
  filePath = p;
  const el = document.getElementById('file-list');
  const fc = document.getElementById('file-content');
  const bc = document.getElementById('file-breadcrumb');
  fc.style.display = 'none'; el.style.display = 'block';
  const parts = p ? p.split('/') : [];
  let crumbs = '<a onclick="loadFiles(\'\')">root</a>';
  let acc = '';
  parts.forEach((seg, i) => { acc += (i ? '/' : '') + seg; crumbs += ' / <a onclick="loadFiles(\'' + acc + '\')">' + seg + '</a>'; });
  bc.innerHTML = crumbs;
  try {
    const r = await fetch(API + '/files?path=' + encodeURIComponent(p));
    const items = await r.json();
    if (items.error) { el.innerHTML = '<li>' + items.error + '</li>'; return; }
    el.innerHTML = items.map(f => {
      const click = f.is_dir ? "loadFiles('" + f.path + "')" : "viewFile('" + f.path + "')";
      const icon = f.is_dir ? '\u{1F4C1}' : '\u{1F4C4}';
      const sz = f.is_dir ? '' : ' <span style="color:var(--text2);font-size:11px;margin-left:auto">' + _fmtSize(f.size) + '</span>';
      return '<li onclick="' + click + '"><span class="file-icon">' + icon + '</span>' + f.name + sz + '</li>';
    }).join('');
  } catch(e) { el.innerHTML = '<li>Error loading files</li>'; }
}
function _fmtSize(b) { if (b < 1024) return b + 'B'; if (b < 1048576) return (b/1024).toFixed(1) + 'K'; return (b/1048576).toFixed(1) + 'M'; }
async function viewFile(p) {
  document.getElementById('file-list').style.display = 'none';
  const fc = document.getElementById('file-content'); fc.style.display = 'block'; fc.textContent = 'Loading\u2026';
  const bc = document.getElementById('file-breadcrumb');
  const dir = p.includes('/') ? p.substring(0, p.lastIndexOf('/')) : '';
  bc.innerHTML = '<a onclick="loadFiles(\'' + dir + '\')">\u2190 back</a> / ' + p.split('/').pop();
  try { const r = await fetch(API + '/files?path=' + encodeURIComponent(p)); fc.textContent = await r.text(); } catch(e) { fc.textContent = 'Error loading file'; }
}
// Notes
async function loadNotes() {
  if (!HAS_NOTES) return;
  const el = document.getElementById('notes-list');
  const nc = document.getElementById('note-content');
  nc.style.display = 'none'; el.style.display = 'block';
  try {
    const r = await fetch(API + '/notes');
    const notes = await r.json();
    el.innerHTML = notes.map(n => '<a class="note-link" onclick="viewNote(\'' + n.path + '\')">' + n.path + '</a>').join('');
  } catch(e) { el.innerHTML = 'Error loading notes'; }
}
async function viewNote(p) {
  document.getElementById('notes-list').style.display = 'none';
  const nc = document.getElementById('note-content'); nc.style.display = 'block'; nc.textContent = 'Loading\u2026';
  try { const r = await fetch(API + '/note/' + encodeURIComponent(p)); const d = await r.json(); nc.textContent = d.content || '(empty)'; } catch(e) { nc.textContent = 'Error'; }
}
loadInfo(); startPoll();
"""


def _share_viewer_html(token: str, session_name: str, perms: str) -> str:
    has_files = "files" in perms
    has_notes = "notes" in perms
    import html as _html
    safe_name = _html.escape(session_name)
    safe_token = _html.escape(token)
    files_tab = '<div class="tab" onclick="switchTab(\'files\')">Files</div>' if has_files else ""
    notes_tab = '<div class="tab" onclick="switchTab(\'notes\')">Notes</div>' if has_notes else ""
    files_panel = ('<div class="panel" id="panel-files"><div class="breadcrumb" id="file-breadcrumb"></div>'
                   '<ul class="file-list" id="file-list"></ul>'
                   '<div class="file-content" id="file-content" style="display:none"></div></div>') if has_files else ""
    notes_panel = ('<div class="panel" id="panel-notes"><div id="notes-list"></div>'
                   '<div class="file-content" id="note-content" style="display:none"></div></div>') if has_notes else ""
    return (
        '<!DOCTYPE html><html lang="en"><head><meta charset="utf-8">'
        '<meta name="viewport" content="width=device-width,initial-scale=1">'
        '<title>' + safe_name + ' \u2014 amux shared session</title>'
        '<style>' + _SHARE_CSS + '</style></head>'
        '<body data-token="' + safe_token + '"'
        ' data-files="' + ("1" if has_files else "0") + '"'
        ' data-notes="' + ("1" if has_notes else "0") + '">'
        '<header><div class="status" id="status-dot"></div>'
        '<h1 id="session-name">' + safe_name + '</h1>'
        '<span id="session-desc" style="color:var(--text2);font-size:12px;"></span></header>'
        '<div class="tabs"><div class="tab active" onclick="switchTab(\'output\')">Output</div>'
        + files_tab + notes_tab + '</div>'
        '<div class="panel active" id="panel-output"><div id="output">Loading\u2026</div></div>'
        + files_panel + notes_panel +
        '<script>' + _SHARE_JS + '</script></body></html>'
    )


RELEASE_NOTES_HTML = """<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta name="theme-color" content="#0a0a0c">
<title>amux — Release Notes</title>
<meta name="description" content="amux release notes and changelog. Every commit, every feature, every fix.">
<meta property="og:title" content="amux Release Notes">
<meta property="og:description" content="Changelog for amux — the Claude session manager. Features, fixes, and everything in between.">
<link rel="canonical" href="/release-notes">
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&display=swap" rel="stylesheet">
<style>
*{box-sizing:border-box;margin:0;padding:0}
:root{--bg:#0a0a0c;--card:#111114;--border:#2a2a30;--text:#e8e8ec;--dim:#a0a0b8;--muted:#707088;--green:#4ade80;--mono:'JetBrains Mono','SF Mono',Consolas,monospace}
body{font-family:'DM Sans',-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;background:var(--bg);color:var(--text);min-height:100vh;line-height:1.5;-webkit-font-smoothing:antialiased}
body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(255,255,255,0.008) 2px,rgba(255,255,255,0.008) 4px);pointer-events:none;z-index:9999}
a{color:var(--green);text-decoration:none}
a:hover{opacity:0.8}
.rn-header{padding:40px 24px 32px;border-bottom:1px solid var(--border);max-width:860px;margin:0 auto}
.rn-logo{display:flex;align-items:center;gap:10px;margin-bottom:24px}
.rn-logo-mark{width:32px;height:32px;background:var(--green);border-radius:6px;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:0.9rem;color:var(--bg);font-family:var(--mono)}
.rn-logo-name{font-size:1.1rem;font-weight:700;color:var(--green);font-family:var(--mono);letter-spacing:-0.03em}
.rn-logo-sep{color:var(--muted);margin:0 4px;font-family:var(--mono)}
.rn-logo-sub{font-size:1.1rem;color:var(--dim);font-family:var(--mono)}
h1.rn-title{font-size:2rem;font-weight:700;margin-bottom:8px;font-family:var(--mono);letter-spacing:-0.04em}
.rn-subtitle{color:var(--dim);font-size:1rem}
.rn-content{max-width:860px;margin:0 auto;padding:0 24px 80px}
.rn-entry{border-bottom:1px solid var(--border);padding:40px 0}
.rn-entry:last-child{border-bottom:none}
.rn-entry-meta{display:flex;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:12px}
.rn-date{font-size:0.8rem;color:var(--dim);font-family:var(--mono)}
.rn-badge{font-size:0.72rem;padding:2px 8px;border-radius:12px;font-weight:600;letter-spacing:0.02em;font-family:var(--mono)}
.rn-badge-feat{background:rgba(74,222,128,0.15);color:#4ade80;border:1px solid rgba(74,222,128,0.3)}
.rn-badge-fix{background:rgba(251,191,36,0.12);color:#fbbf24;border:1px solid rgba(251,191,36,0.3)}
.rn-badge-chore{background:rgba(136,136,160,0.15);color:var(--dim);border:1px solid rgba(136,136,160,0.25)}
.rn-tag{font-size:0.72rem;padding:2px 8px;border-radius:12px;background:rgba(74,222,128,0.1);color:#4ade80;border:1px solid rgba(74,222,128,0.2);font-family:var(--mono)}
.rn-commit{font-family:var(--mono);font-size:0.78rem;color:var(--dim);background:var(--card);border:1px solid var(--border);border-radius:6px;padding:2px 8px}
.rn-commit:hover{color:var(--green);border-color:var(--green)}
.rn-entry-title{font-size:1.25rem;font-weight:600;margin-bottom:10px;color:var(--text);font-family:var(--mono);letter-spacing:-0.02em}
.rn-entry-desc{color:var(--dim);font-size:0.9rem;line-height:1.7;margin-bottom:20px;max-width:680px}
.rn-video-wrap{border-radius:10px;overflow:hidden;background:var(--card);border:1px solid var(--border);margin-top:4px;aspect-ratio:16/9;max-width:680px;position:relative}
.rn-video-wrap video{width:100%;height:100%;display:block;object-fit:contain;background:var(--bg)}
.rn-video-placeholder{width:100%;height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;color:var(--muted);font-size:0.85rem;aspect-ratio:16/9;max-width:680px;background:var(--card);border:1px solid var(--border);border-radius:10px}
.rn-video-placeholder svg{opacity:0.4}
.rn-load-more{display:flex;justify-content:center;padding:32px 0}
.rn-load-btn{background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:8px;padding:10px 24px;font-size:0.9rem;cursor:pointer;transition:border-color 0.15s;font-family:var(--mono)}
.rn-load-btn:hover{border-color:var(--green);color:var(--green)}
.rn-spinner{display:flex;justify-content:center;padding:40px;color:var(--muted);font-size:0.85rem}
.rn-empty{text-align:center;padding:80px 24px;color:var(--muted)}
.rn-sentinel{height:1px}
@media(max-width:600px){
  .rn-header{padding:24px 16px 20px}
  h1.rn-title{font-size:1.5rem}
  .rn-content{padding:0 16px 60px}
  .rn-entry{padding:28px 0}
  .rn-entry-title{font-size:1.1rem}
}
</style>
</head>
<body>
<header class="rn-header">
  <div class="rn-logo">
    <div class="rn-logo-mark">a</div>
    <a href="/" class="rn-logo-name">amux</a>
    <span class="rn-logo-sep">/</span>
    <span class="rn-logo-sub">release notes</span>
  </div>
  <h1 class="rn-title">Release Notes</h1>
  <p class="rn-subtitle">Every commit. Every feature. Every fix.</p>
</header>
<div class="rn-content">
  <div id="rn-list"></div>
  <div class="rn-sentinel" id="rn-sentinel"></div>
  <div class="rn-spinner" id="rn-spinner" style="display:none">Loading&hellip;</div>
</div>
<script>
const GH_RAW = 'https://raw.githubusercontent.com/mixpeek/amux/main/docs/release-notes/videos/';
const GH_COMMIT = 'https://github.com/mixpeek/amux/commit/';
let page = 0, loading = false, done = false;

function typeBadge(type) {
  const cls = type === 'feat' ? 'feat' : type === 'fix' ? 'fix' : 'chore';
  return `<span class="rn-badge rn-badge-${cls}">${type}</span>`;
}

function renderEntry(n) {
  const tags = (n.tags||[]).map(t => `<span class="rn-tag">${t}</span>`).join('');
  const video = n.video
    ? `<div class="rn-video-wrap"><video controls preload="none" poster="">
        <source src="${GH_RAW}${n.video}" type="video/mp4">
       </video></div>`
    : `<div class="rn-video-placeholder">
        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="5 3 19 12 5 21 5 3"/></svg>
        <span>Video coming soon</span>
       </div>`;
  return `<article class="rn-entry" data-hash="${n.hash}">
    <div class="rn-entry-meta">
      <span class="rn-date">${n.date}</span>
      ${typeBadge(n.type)}
      ${tags}
      <a class="rn-commit" href="${GH_COMMIT}${n.hash}" target="_blank" rel="noopener">${n.short}</a>
    </div>
    <h2 class="rn-entry-title">${n.title}</h2>
    <p class="rn-entry-desc">${n.description}</p>
    ${video}
  </article>`;
}

async function loadMore() {
  if (loading || done) return;
  loading = true;
  document.getElementById('rn-spinner').style.display = 'flex';
  page++;
  try {
    const r = await fetch('/api/release-notes?page=' + page + '&per_page=5');
    const d = await r.json();
    const list = document.getElementById('rn-list');
    d.notes.forEach(n => list.insertAdjacentHTML('beforeend', renderEntry(n)));
    if (!d.has_more) {
      done = true;
      document.getElementById('rn-sentinel').remove();
      if (!d.notes.length && page === 1) {
        list.innerHTML = '<div class="rn-empty">No release notes yet.</div>';
      }
    }
  } catch(e) { console.error(e); }
  loading = false;
  document.getElementById('rn-spinner').style.display = 'none';
}

// IntersectionObserver for lazy loading
const sentinel = document.getElementById('rn-sentinel');
const obs = new IntersectionObserver(entries => {
  if (entries[0].isIntersecting) loadMore();
}, { rootMargin: '200px' });
obs.observe(sentinel);

// Load first batch immediately
loadMore();
</script>
</body>
</html>"""

